  1→/**
  2→ * Tests for sequant_run MCP tool async refactor
  3→ * Issue #388: Replace spawnSync with async spawn
  4→ *
  5→ * Covers:
  6→ * - AC-1: spawn instead of spawnSync
  7→ * - AC-4: Output buffered, truncated to 2000 chars
  8→ * - AC-5: Timeout preserved (30 min default)
  9→ * - AC-6: Tests updated for async
 10→ * - Derived AC-7: Handle ENOENT with descriptive error
 11→ * - Derived AC-8: No orphan processes on timeout/cancel
 12→ * - AC-3: MCP cancellation via AbortSignal
 13→ */
 14→
 15→import { describe, it, expect, vi, beforeEach, afterEach } from "vitest";
 16→import { EventEmitter } from "events";
 17→import { spawn } from "child_process";
 18→
 19→// Mock child_process before importing server
 20→vi.mock("child_process", async (importOriginal) => {
 21→  const actual = await importOriginal<typeof import("child_process")>();
 22→  return {
 23→    ...actual,
 24→    spawn: vi.fn(),
 25→  };
 26→});
 27→
 28→const mockedSpawn = vi.mocked(spawn);
 29→
 30→/** Create a mock ChildProcess that emits events asynchronously */
 31→function createMockProcess(opts: {
 32→  exitCode?: number | null;
 33→  stdout?: string;
 34→  stderr?: string;
 35→  error?: Error;
 36→  /** Delay in ms before emitting events (default: 0 = microtask) */
 37→  delay?: number;
 38→}) {
 39→  const proc = new EventEmitter() as ReturnType<typeof spawn>;
 40→  const stdoutEmitter = new EventEmitter();
 41→  const stderrEmitter = new EventEmitter();
 42→  (proc as unknown as Record<string, unknown>).stdout = stdoutEmitter;
 43→  (proc as unknown as Record<string, unknown>).stderr = stderrEmitter;
 44→  (proc as unknown as Record<string, unknown>).pid = 12345;
 45→  (proc as unknown as Record<string, unknown>).killed = false;
 46→  (proc as unknown as Record<string, unknown>).kill = vi.fn(() => {
 47→    (proc as unknown as Record<string, unknown>).killed = true;
 48→  });
 49→
 50→  const emit = () => {
 51→    if (opts.stdout) {
 52→      stdoutEmitter.emit("data", Buffer.from(opts.stdout));
 53→    }
 54→    if (opts.stderr) {
 55→      stderrEmitter.emit("data", Buffer.from(opts.stderr));
 56→    }
 57→    if (opts.error) {
 58→      proc.emit("error", opts.error);
 59→    } else {
 60→      proc.emit("close", opts.exitCode ?? 0);
 61→    }
 62→  };
 63→
 64→  if (opts.delay) {
 65→    setTimeout(emit, opts.delay);
 66→  } else {
 67→    queueMicrotask(emit);
 68→  }
 69→
 70→  return proc;
 71→}
 72→
 73→// Check if MCP SDK is available
 74→const mcpSdkAvailable = await import("@modelcontextprotocol/sdk/server/mcp.js")
 75→  .then(() => true)
 76→  .catch(() => false);
 77→
 78→describe.skipIf(!mcpSdkAvailable)("sequant_run tool async refactor", () => {
 79→  // eslint-disable-next-line @typescript-eslint/no-explicit-any
 80→  let client: any;
 81→  let cleanup: () => Promise<void>;
 82→
 83→  beforeEach(async () => {
 84→    vi.clearAllMocks();
 85→
 86→    const { createServer } = await import("../src/mcp/server.js");
 87→    const { Client } =
 88→      await import("@modelcontextprotocol/sdk/client/index.js");
 89→    const { InMemoryTransport } =
 90→      await import("@modelcontextprotocol/sdk/inMemory.js");
 91→
 92→    const server = createServer("1.0.0-test");
 93→    const clientInstance = new Client({
 94→      name: "test-client",
 95→      version: "1.0.0",
 96→    });
 97→
 98→    const [clientTransport, serverTransport] =
 99→      InMemoryTransport.createLinkedPair();
100→    await Promise.all([
101→      clientInstance.connect(clientTransport),
102→      server.connect(serverTransport),
103→    ]);
104→
105→    client = clientInstance;
106→    cleanup = async () => {
107→      await clientInstance.close();
108→      await server.close();
109→    };
110→  });
111→
112→  afterEach(async () => {
113→    await cleanup();
114→  });
115→
116→  describe("AC-1: spawn instead of spawnSync", () => {
117→    it("should use child_process.spawn and return Promise that resolves after process exit", async () => {
118→      mockedSpawn.mockImplementation(() =>
119→        createMockProcess({ exitCode: 0, stdout: "success output" }),
120→      );
121→
122→      const result = await client.callTool({
123→        name: "sequant_run",
124→        arguments: { issues: [123] },
125→      });
126→
127→      expect(mockedSpawn).toHaveBeenCalledOnce();
128→      expect(result).toBeDefined();
129→      expect(result.content).toHaveLength(1);
130→      expect(result.isError).toBeFalsy();
131→    });
132→
133→    it("should call spawn with npx and correct command arguments", async () => {
134→      mockedSpawn.mockImplementation(() =>
135→        createMockProcess({ exitCode: 0, stdout: "" }),
136→      );
137→
138→      await client.callTool({
139→        name: "sequant_run",
140→        arguments: { issues: [42] },
141→      });
142→
143→      expect(mockedSpawn).toHaveBeenCalledWith(
144→        "npx",
145→        ["sequant", "run", "42", "--log-json"],
146→        expect.objectContaining({
147→          stdio: ["pipe", "pipe", "pipe"],
148→          detached: true,
149→          env: expect.objectContaining({
150→            SEQUANT_ORCHESTRATOR: "mcp-server",
151→          }),
152→        }),
153→      );
154→    });
155→  });
156→
157→  describe("AC-4: Output buffered, truncated to 2000 chars", () => {
158→    it("should truncate stdout to last 2000 chars when output exceeds limit", async () => {
159→      const largeOutput = "x".repeat(5000);
160→      mockedSpawn.mockImplementation(() =>
161→        createMockProcess({ exitCode: 0, stdout: largeOutput }),
162→      );
163→
164→      const result = await client.callTool({
165→        name: "sequant_run",
166→        arguments: { issues: [456] },
167→      });
168→
169→      const data = JSON.parse(
170→        (result.content as Array<{ type: string; text: string }>)[0].text,
171→      );
172→      expect(data.output.length).toBeLessThanOrEqual(2000);
173→      expect(data.output).toBe("x".repeat(2000));
174→    });
175→
176→    it("should return full output when it's smaller than 2000 chars", async () => {
177→      const smallOutput = "hello world";
178→      mockedSpawn.mockImplementation(() =>
179→        createMockProcess({ exitCode: 0, stdout: smallOutput }),
180→      );
181→
182→      const result = await client.callTool({
183→        name: "sequant_run",
184→        arguments: { issues: [457] },
185→      });
186→
187→      const data = JSON.parse(
188→        (result.content as Array<{ type: string; text: string }>)[0].text,
189→      );
190→      expect(data.output).toBe("hello world");
191→    });
192→
193→    it("should handle empty output gracefully", async () => {
194→      mockedSpawn.mockImplementation(() => createMockProcess({ exitCode: 0 }));
195→
196→      const result = await client.callTool({
197→        name: "sequant_run",
198→        arguments: { issues: [458] },
199→      });
200→
201→      const data = JSON.parse(
202→        (result.content as Array<{ type: string; text: string }>)[0].text,
203→      );
204→      expect(data.output).toBe("");
205→    });
206→  });
207→
208→  describe("AC-5: Timeout preserved (30 min default)", () => {
209→    it("should reject with timeout error when process does not exit in time", async () => {
210→      // Test spawnAsync directly with a short timeout to avoid MCP transport interference
211→      const { spawnAsync } = await import("../src/mcp/tools/run.js");
212→
213→      // Create a process that never exits
214→      const proc = new EventEmitter() as ReturnType<typeof spawn>;
215→      const stdoutEmitter = new EventEmitter();
216→      const stderrEmitter = new EventEmitter();
217→      (proc as unknown as Record<string, unknown>).stdout = stdoutEmitter;
218→      (proc as unknown as Record<string, unknown>).stderr = stderrEmitter;
219→      (proc as unknown as Record<string, unknown>).pid = 99999;
220→      (proc as unknown as Record<string, unknown>).killed = false;
221→      (proc as unknown as Record<string, unknown>).kill = vi.fn();
222→
223→      mockedSpawn.mockReturnValue(proc);
224→
225→      // Use a very short timeout (50ms) for fast testing
226→      await expect(
227→        spawnAsync("npx", ["test"], { timeout: 50 }),
228→      ).rejects.toThrow("timed out");
229→    }, 10000);
230→
231→    it("should complete normally when process exits before timeout", async () => {
232→      mockedSpawn.mockImplementation(() =>
233→        createMockProcess({ exitCode: 0, stdout: "done" }),
234→      );
235→
236→      const result = await client.callTool({
237→        name: "sequant_run",
238→        arguments: { issues: [790] },
239→      });
240→
241→      expect(result.isError).toBeFalsy();
242→      const data = JSON.parse(
243→        (result.content as Array<{ type: string; text: string }>)[0].text,
244→      );
245→      expect(data.status).toBe("success");
246→    });
247→  });
248→
249→  describe("AC-6: Tests updated for async", () => {
250→    it("should return success status with valid issue numbers", async () => {
251→      mockedSpawn.mockImplementation(() =>
252→        createMockProcess({ exitCode: 0, stdout: "test output" }),
253→      );
254→
255→      const result = await client.callTool({
256→        name: "sequant_run",
257→        arguments: { issues: [111] },
258→      });
259→
260→      expect(result.isError).toBeFalsy();
261→      const data = JSON.parse(
262→        (result.content as Array<{ type: string; text: string }>)[0].text,
263→      );
264→      expect(data.status).toBe("success");
265→      expect(data.issues).toEqual([111]);
266→    });
267→
268→    it("should return error for empty issues array", async () => {
269→      const result = await client.callTool({
270→        name: "sequant_run",
271→        arguments: { issues: [] },
272→      });
273→
274→      expect(result.isError).toBe(true);
275→      const data = JSON.parse(
276→        (result.content as Array<{ type: string; text: string }>)[0].text,
277→      );
278→      expect(data.error).toBe("INVALID_INPUT");
279→    });
280→
281→    it("should return failure status with non-zero exit code", async () => {
282→      mockedSpawn.mockImplementation(() =>
283→        createMockProcess({
284→          exitCode: 2,
285→          stdout: "partial",
286→          stderr: "fatal error",
287→        }),
288→      );
289→
290→      const result = await client.callTool({
291→        name: "sequant_run",
292→        arguments: { issues: [112] },
293→      });
294→
295→      expect(result.isError).toBe(true);
296→      const data = JSON.parse(
297→        (result.content as Array<{ type: string; text: string }>)[0].text,
298→      );
299→      expect(data.status).toBe("failure");
300→      expect(data.exitCode).toBe(2);
301→      expect(data.error).toContain("fatal error");
302→    });
303→  });
304→
305→  describe("Derived AC-7: Handle ENOENT with descriptive error", () => {
306→    it("should return EXECUTION_ERROR with descriptive message when spawn emits ENOENT", async () => {
307→      const error = new Error("ENOENT: no such file or directory");
308→      (error as NodeJS.ErrnoException).code = "ENOENT";
309→      mockedSpawn.mockImplementation(() => createMockProcess({ error }));
310→
311→      const result = await client.callTool({
312→        name: "sequant_run",
313→        arguments: { issues: [222] },
314→      });
315→
316→      expect(result.isError).toBe(true);
317→      const data = JSON.parse(
