  1→/**
  2→ * sequant_run MCP tool
  3→ *
  4→ * Execute workflow phases for GitHub issues.
  5→ * Uses async spawn to keep the MCP server responsive during execution.
  6→ */
  7→
  8→import { z } from "zod";
  9→import type { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
 10→import { spawn } from "child_process";
 11→
 12→const runToolInputSchema = {
 13→  issues: z.array(z.number()).describe("GitHub issue numbers to process"),
 14→  phases: z
 15→    .string()
 16→    .optional()
 17→    .describe("Comma-separated phases (default: spec,exec,qa)"),
 18→  qualityLoop: z
 19→    .boolean()
 20→    .optional()
 21→    .describe("Enable auto-retry on QA failure"),
 22→  agent: z
 23→    .string()
 24→    .optional()
 25→    .describe("Agent driver for phase execution (default: configured default)"),
 26→};
 27→
 28→export function registerRunTool(server: McpServer): void {
 29→  server.registerTool(
 30→    "sequant_run",
 31→    {
 32→      title: "Sequant Run",
 33→      description:
 34→        "Run structured AI workflow phases (spec, exec, qa) for GitHub issues with quality gates",
 35→      inputSchema: runToolInputSchema,
 36→    },
 37→    (async (
 38→      {
 39→        issues,
 40→        phases,
 41→        qualityLoop,
 42→        agent,
 43→      }: {
 44→        issues: number[];
 45→        phases?: string;
 46→        qualityLoop?: boolean;
 47→        agent?: string;
 48→      },
 49→      extra: { signal: AbortSignal },
 50→    ) => {
 51→      if (!issues || issues.length === 0) {
 52→        return {
 53→          content: [
 54→            {
 55→              type: "text" as const,
 56→              text: JSON.stringify({
 57→                error: "INVALID_INPUT",
 58→                message: "At least one issue number is required",
 59→              }),
 60→            },
 61→          ],
 62→          isError: true,
 63→        };
 64→      }
 65→
 66→      // Build command arguments
 67→      const args = ["sequant", "run", ...issues.map(String)];
 68→      if (phases) {
 69→        args.push("--phases", phases);
 70→      }
 71→      if (qualityLoop) {
 72→        args.push("--quality-loop");
 73→      }
 74→      if (agent) {
 75→        args.push("--agent", agent);
 76→      }
 77→      args.push("--log-json");
 78→
 79→      try {
 80→        const result = await spawnAsync("npx", args, {
 81→          timeout: 1800000, // 30 min default
 82→          env: {
 83→            ...process.env,
 84→            SEQUANT_ORCHESTRATOR: "mcp-server",
 85→          },
 86→          signal: extra.signal,
 87→        });
 88→
 89→        if (result.exitCode !== 0) {
 90→          return {
 91→            content: [
 92→              {
 93→                type: "text" as const,
 94→                text: JSON.stringify({
 95→                  status: "failure",
 96→                  exitCode: result.exitCode,
