        process.kill(-proc.pid, signal);
      }
    } catch {
      // Process group may already be gone — fall back to direct kill
      if (!proc.killed) {
        proc.kill(signal);
      }
    }
  };

  sendSignal("SIGTERM");

  // Escalate to SIGKILL if process doesn't exit
  setTimeout(() => {
    if (!proc.killed) {
      sendSignal("SIGKILL");
    }
  }, SIGKILL_GRACE_MS).unref();
}
